#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


vec2 huv=uTexSize.zw*0.5;
vec2 aspc=vec2(q2,q1);
vec3 tuv;
vec3 pq;
vec3 my_scale;
vec3 st,op,prj,prjN,surfp,sref,pln,b2,bpr,b3;
float mscale,i,cp,sp,pdist;
my_scale=texture(sampler_pw_main,vec2(q20,0.007));
mscale=3/(my_scale.z+1);


st.xy=(vUv.xy-0.5+vec3(q4,q5,q6)*0.3)*3.5*aspc;
st.z=1;
op.xy=st.xy*(2+my_scale.y*mscale);
op.z=-1;
op=multiply(op,rot_f1);
st=multiply(st,rot_f1);
op+=vec3(q3,q4,q5)*0.8;
st+=vec3(q3,q4,q5)*0.8;
pdist=-10;
prj=op-st;
prjN=normalize(prj);

//op=op*0.6+i*0.4;
pln.z=dot(prjN,vec3(0,0,1)); //cosine to plane
sp=dot(op,vec3(0,0,1));
surfp=op-prjN*(1/pln.zzz)*(sp+0.5);
pln.x=dot(surfp,vec3(1,0,0)); //cosine to plane
pln.y=dot(surfp,vec3(0,1,0)); //cosine to plane
tuv.xyz=pln.z>0?( (abs(pln.x)<0.5)&&(abs(pln.y)<0.5)?pln.xyz:-5):-5;

//pln.z=dot(prjN,vec3(0,0,-1)); //cosine to plane
//sp=dot(op,vec3(0,0,-1));
pln.z=-pln.z;
sp=-sp;
surfp=op-prjN*(1/pln.zzz)*(sp+0.5);
pln.x=dot(surfp,vec3(1,0,0)); //cosine to plane
pln.y=dot(surfp,vec3(0,1,0)); //cosine to plane
tuv.xyz=pln.z>0?( (abs(pln.x)<0.5)&&(abs(pln.y)<0.5)?pln.xyz:tuv):tuv;

pln.y=dot(prjN,vec3(0,1,0)); //cosine to plane
sp=dot(op,vec3(0,1,0));
surfp=op-prjN*(1/pln.yyy)*(sp+0.5);
pln.x=dot(surfp,vec3(1,0,0)); //cosine to plane
pln.z=dot(surfp,vec3(0,0,1)); //cosine to plane
tuv.xyz=pln.y>0?( (abs(pln.x)<0.5)&&(abs(pln.z)<0.5)?pln.xzy:tuv):tuv;

//pln.y=dot(prjN,vec3(0,-1,0)); //cosine to plane
//sp=dot(op,vec3(0,-1,0));
pln.y=-pln.y;
sp=-sp;
surfp=op-prjN*(1/pln.yyy)*(sp+0.5);
pln.x=dot(surfp,vec3(1,0,0)); //cosine to plane
pln.z=dot(surfp,vec3(0,0,1)); //cosine to plane
tuv.xyz=pln.y>0?( (abs(pln.x)<0.5)&&(abs(pln.z)<0.5)?pln.xzy:tuv):tuv;

pln.x=dot(prjN,vec3(1,0,0)); //cosine to plane
sp=dot(op,vec3(1,0,0));
surfp=op-prjN*(1/pln.xxx)*(sp+0.5);
pln.y=dot(surfp,vec3(0,1,0)); //cosine to plane
pln.z=dot(surfp,vec3(0,0,1)); //cosine to plane
tuv.xyz=pln.x>0?( (abs(pln.y)<0.5)&&(abs(pln.z)<0.5)?pln.yzx:tuv):tuv;

//pln.x=dot(prjN,vec3(-1,0,0)); //cosine to plane
//sp=dot(op,vec3(-1,0,0));
pln.x=-pln.x;
sp=-sp;
surfp=op-prjN*(1/pln.xxx)*(sp+0.5);
pln.y=dot(surfp,vec3(0,1,0)); //cosine to plane
pln.z=dot(surfp,vec3(0,0,1)); //cosine to plane
tuv.xyz=pln.x>0?( (abs(pln.y)<0.5)&&(abs(pln.z)<0.5)?pln.yzx:tuv):tuv;

sp=tuv.x;


//b2=texture(base02,sqrt(1-prjN.yz*prjN.yz)/prjN.xx*20);//abs(prjN.z+2))*0.7;

vec3 t1,t2,a1,a2;


/*
b2=texture(base02,-3*prjN.yz/(prjN.xx*prjN.xx*2-3));//abs(prjN.z+2))*0.7;
b2=max(b2,texture(base02,-3*prjN.xy/(prjN.zz*prjN.zz*2-3)));//abs(prjN.z+2))*0.7;
b2=max(b2,texture(base02,-3*prjN.xz/(prjN.yy*prjN.yy*2-3)));//abs(prjN.z+2))*0.7;

b3=texture(base0,3*prjN.yz/(prjN.xx*prjN.xx*2-3));//abs(prjN.z+2))*0.7;
b3=max(b3,texture(base01,3*prjN.xy/(prjN.zz*prjN.zz*2-3)));//abs(prjN.z+2))*0.7;
b3=max(b3,texture(base01,3*prjN.xz/(prjN.yy*prjN.yy*2-3)));//abs(prjN.z+2))*0.7;
*/
//a1=flaot3(prjN.x,prjN.y,0);
//a2=flaot3(prjN.x,prjN.y,0);


b2=texture(base01,sin(prjN.xy*M_PI))*abs(prjN.zzz);
b2=max(b2,texture(base01,sin(prjN.xz*M_PI))*abs(prjN.yyy));
b2=max(b2,texture(base01,sin(prjN.yz*M_PI))*abs(prjN.xxx));

b3=texture(base02,sin(prjN.xy*M_PI*0.985))*abs(prjN.zzz);
b3=max(b3,texture(base02,sin(prjN.xz*0.985*M_PI))*abs(prjN.yyy));
b3=max(b3,texture(base02,sin(prjN.yz*0.985*M_PI))*abs(prjN.xxx));

//b2*=0.33333;
//pln=b2*0.95+0.05*texture(base01,vUv);//(tuv.xy-0.5)*(tuv.zz*0.1+1));

//pdist=max(b2.x,max(b2.y,b2.z));
//pdist=max(pln.x,max(pln.y,pln.z));

pdist=0.33333*(b2.x+b2.y+b2.z);
//pdist=pdist*pdist;
i=texture(sampler_pw_main,vec2(q20,pdist));
i=i>my_scale.y*0.5?i*mscale:i+my_scale.y*0.5;
//i*=mscale;

cp=i;

//pln=texture(base02,(tuv.xy-0.5));
//tuv=reflect(normalize(tuv),normalize(vec3(vUv.x,vUv.y,-3)));//,cp*1.3+0.5);

//ret=tex2d(base01,(vUv-0.5)*(1.01-cp*0.02)+0.5+/*prjN.yz*/(op.xz/abs((op.yy*2)+30))*0.03);
//ret=ret*(0.6*(cp)+0.4)+b2*0.4*cp;

//ret=ret+(0.2-0.2*cp)*b2;

//ret=ret.xyz*1.0-((cp*0.2)*tex2d(base01,(vUv-0.5)*(1.01-cp*0.02)/*prjN.xy*prjN.yz*-prjN.xz*/+0.5).xyz);

pln=texture(base02,(tuv.xy-0.5))*0.2;
pln+=(0.8-cp*0.6)*texture(base01,0.5+(0.5*tuv.xy-0.5)*abs(tuv.zz*0.02+2));



ret=(1-i)*b2+b3*i*i*0.8;//*0.5+0.5*pln;
ret=mix(ret,tex2d(sampler_fw_main,
(prjN.xy/abs(prjN.zz+2))*0.016+(vUv-0.5-0.016*(prjN.xy/abs(prjN.zz+2)))*(1-i*0.04)+0.5),
0.99-(0.85*(1-i)));


ret=sp>-5?pln*(0.4+(cp*0.6))

 /*texture(base02,tuv.xy+0.5)*/:ret;
//ret+=vec3(0.01,0,0.012);
//ret.xy=tuv.xy*0.5+0.5;
ret=tuv.z>0?ret*pow(tuv.zzz*1.5,2)+(0.2*tuv.zzz):ret;

//vUv=vUv*0;
//ret=vUv.x<i?ret:0;
//ret*=0.5;

//ret=tuv>-4?tuv*0.5+0.5:vec3(vUv.x,vUv.y,1);

  fragColor = ret;
}

